package cl.duoc.vetcontrol.venta.controller;
import cl.duoc.vetcontrol.venta.dto.VentaRequest; import cl.duoc.vetcontrol.venta.model.Venta; import cl.duoc.vetcontrol.venta.service.VentaService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/ventas")
public class VentaController { private final VentaService service; public VentaController(VentaService service){this.service=service;} @GetMapping public ResponseEntity<List<Venta>> all(){return ResponseEntity.ok(service.all());} @GetMapping("/{id}") public ResponseEntity<Venta> one(@PathVariable Long id){return ResponseEntity.ok(service.one(id));} @GetMapping("/clientes/{clienteId}") public ResponseEntity<List<Venta>> byCliente(@PathVariable Long clienteId){return ResponseEntity.ok(service.byCliente(clienteId));} @PostMapping public ResponseEntity<Venta> create(@Valid @RequestBody VentaRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));} }
